// Repository: só a assinatura — Spring Data JPA gera a query pelo nome do método
public interface TopicRepository extends JpaRepository<Topic, Long> {
    Optional<Topic> findBySlug(String slug); // vira "SELECT * FROM topic WHERE slug = ?"
}

// Service: lógica de negócio, orquestra o Repository
@Service
public class TopicService {
    private final TopicRepository topicRepository;

    public TopicService(TopicRepository topicRepository) {
        this.topicRepository = topicRepository;
    }

    public TopicDetailResponse buscarPorSlug(String slug) {
        Topic topic = topicRepository.findBySlug(slug)
            .orElseThrow(() -> new TopicNotFoundException(slug));
        return converterParaDto(topic); // regra de negócio: transformar Entity em DTO
    }
}

