@Service // bean gerenciado pelo Spring — especialização semântica de @Component
public class TopicService {

    // @Cacheable: registra o retorno deste método no cache "topics-list".
    // Chamadas seguintes retornam o valor cacheado sem re-executar a query no banco.
    @Cacheable("topics-list")
    public Map<Category, List<TopicSummaryResponse>> listarAgrupados() {
        return topicRepository.findAllByOrderByCategoryAscOrderIndexAsc().stream()
            .map(this::paraResumo)
            .collect(Collectors.groupingBy(TopicSummaryResponse::category));
    }
}

